import{_ as e,o as a,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Audit Log","description":"","frontmatter":{},"headers":[],"relativePath":"guide/audit-log.md","filePath":"guide/audit-log.md"}'),o={name:"guide/audit-log.md"};function r(n,t,d,l,h,c){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="audit-log" tabindex="-1">Audit Log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit Log&quot;">​</a></h1><p>The Audit Log is a complete, tamper-evident record of every significant action performed within GeniusHRM. It captures who did what, when, from which IP address, and what changed.</p><hr><h2 id="accessing-the-audit-log" tabindex="-1">Accessing the Audit Log <a class="header-anchor" href="#accessing-the-audit-log" aria-label="Permalink to &quot;Accessing the Audit Log&quot;">​</a></h2><p>Navigate to <strong>Admin Panel → Audit Log</strong> or go to <code>/admin/audit-log</code>. Only users with the <strong>Admin</strong> role can access the audit log by default. This can be adjusted via <strong>Roles &amp; Permissions</strong> by granting the <code>audit-log.view</code> permission to other roles.</p><hr><h2 id="what-is-logged" tabindex="-1">What Is Logged <a class="header-anchor" href="#what-is-logged" aria-label="Permalink to &quot;What Is Logged&quot;">​</a></h2><p>The audit log captures the following event types across all modules:</p><table tabindex="0"><thead><tr><th>Event Type</th><th>Example</th></tr></thead><tbody><tr><td><strong>Created</strong></td><td>New employee added</td></tr><tr><td><strong>Updated</strong></td><td>Employee salary changed</td></tr><tr><td><strong>Deleted</strong></td><td>Leave request cancelled</td></tr><tr><td><strong>Approved</strong></td><td>Leave request approved</td></tr><tr><td><strong>Rejected</strong></td><td>Leave request rejected</td></tr><tr><td><strong>Login</strong></td><td>User logged in</td></tr><tr><td><strong>Logout</strong></td><td>User logged out</td></tr><tr><td><strong>Failed Login</strong></td><td>Invalid password attempt</td></tr><tr><td><strong>Password Reset</strong></td><td>Password changed</td></tr><tr><td><strong>Settings Changed</strong></td><td>SMTP credentials updated</td></tr><tr><td><strong>Payroll Run</strong></td><td>Payroll cycle started or approved</td></tr><tr><td><strong>Role Changed</strong></td><td>User role updated</td></tr><tr><td><strong>Permission Changed</strong></td><td>Role permissions modified</td></tr></tbody></table><hr><h2 id="audit-log-entry-structure" tabindex="-1">Audit Log Entry Structure <a class="header-anchor" href="#audit-log-entry-structure" aria-label="Permalink to &quot;Audit Log Entry Structure&quot;">​</a></h2><p>Each log entry records:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Timestamp</strong></td><td>Exact date and time of the action (UTC)</td></tr><tr><td><strong>User</strong></td><td>Name and email of the user who performed the action</td></tr><tr><td><strong>IP Address</strong></td><td>Client IP address</td></tr><tr><td><strong>Module</strong></td><td>Which module was affected (e.g., <code>Employees</code>, <code>Payroll</code>)</td></tr><tr><td><strong>Action</strong></td><td>The type of event (<code>created</code>, <code>updated</code>, <code>deleted</code>, etc.)</td></tr><tr><td><strong>Resource</strong></td><td>The specific record affected (e.g., Employee #EMP-042)</td></tr><tr><td><strong>Old Values</strong></td><td>Previous field values (for updates)</td></tr><tr><td><strong>New Values</strong></td><td>Updated field values (for updates)</td></tr></tbody></table><h3 id="example-log-entry" tabindex="-1">Example Log Entry <a class="header-anchor" href="#example-log-entry" aria-label="Permalink to &quot;Example Log Entry&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-04-03 14:22:11 UTC</span></span>
<span class="line"><span>User: Jane Smith (hr@geniushrm.test)</span></span>
<span class="line"><span>IP: 192.168.1.45</span></span>
<span class="line"><span>Module: Employees</span></span>
<span class="line"><span>Action: Updated</span></span>
<span class="line"><span>Resource: Employee #EMP-042 (John Doe)</span></span>
<span class="line"><span>Changes:</span></span>
<span class="line"><span>  - department: &quot;Engineering&quot; → &quot;Product&quot;</span></span>
<span class="line"><span>  - position: &quot;Senior Developer&quot; → &quot;Lead Developer&quot;</span></span></code></pre></div><hr><h2 id="filtering-the-audit-log" tabindex="-1">Filtering the Audit Log <a class="header-anchor" href="#filtering-the-audit-log" aria-label="Permalink to &quot;Filtering the Audit Log&quot;">​</a></h2><p>The audit log supports multiple simultaneous filters to help you find specific events quickly.</p><h3 id="available-filters" tabindex="-1">Available Filters <a class="header-anchor" href="#available-filters" aria-label="Permalink to &quot;Available Filters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Free-text search across user name, email, and resource description</td></tr><tr><td><strong>User</strong></td><td>Filter by specific user (dropdown of all users)</td></tr><tr><td><strong>Module</strong></td><td>Filter by module (Employees, Payroll, Attendance, etc.)</td></tr><tr><td><strong>Action</strong></td><td>Filter by event type (created, updated, deleted, login, etc.)</td></tr><tr><td><strong>Date From</strong></td><td>Show entries from this date (inclusive)</td></tr><tr><td><strong>Date To</strong></td><td>Show entries up to this date (inclusive)</td></tr><tr><td><strong>IP Address</strong></td><td>Filter by specific client IP (useful for security investigations)</td></tr></tbody></table><h3 id="using-date-range-filters" tabindex="-1">Using Date Range Filters <a class="header-anchor" href="#using-date-range-filters" aria-label="Permalink to &quot;Using Date Range Filters&quot;">​</a></h3><p>To view all payroll-related activity for a specific month:</p><ol><li>Set <strong>Module</strong> to <code>Payroll</code></li><li>Set <strong>Date From</strong> to <code>2026-04-01</code></li><li>Set <strong>Date To</strong> to <code>2026-04-30</code></li><li>Click <strong>Apply Filters</strong></li></ol><hr><h2 id="viewing-change-details" tabindex="-1">Viewing Change Details <a class="header-anchor" href="#viewing-change-details" aria-label="Permalink to &quot;Viewing Change Details&quot;">​</a></h2><p>For <code>updated</code> events, click <strong>View Changes</strong> to see a detailed diff:</p><ul><li>Fields that were changed are highlighted</li><li>Old values are shown in red</li><li>New values are shown in green</li><li>Unchanged fields are not shown</li></ul><hr><h2 id="exporting-the-audit-log" tabindex="-1">Exporting the Audit Log <a class="header-anchor" href="#exporting-the-audit-log" aria-label="Permalink to &quot;Exporting the Audit Log&quot;">​</a></h2><p>The audit log can be exported to CSV for archiving, compliance, or further analysis in spreadsheet tools.</p><h3 id="export-steps" tabindex="-1">Export Steps <a class="header-anchor" href="#export-steps" aria-label="Permalink to &quot;Export Steps&quot;">​</a></h3><ol><li>Apply any desired filters to narrow the data set</li><li>Click <strong>Export CSV</strong> (top right of the log table)</li><li>The file downloads immediately as <code>audit-log-YYYY-MM-DD.csv</code></li></ol><h3 id="csv-columns" tabindex="-1">CSV Columns <a class="header-anchor" href="#csv-columns" aria-label="Permalink to &quot;CSV Columns&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>timestamp,user_name,user_email,ip_address,module,action,resource,old_values,new_values</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Compliance Archiving</p><p>For compliance purposes (e.g., GDPR, SOC 2), export the audit log monthly and store the CSVs in a secure, off-site location. GeniusHRM retains log entries indefinitely by default.</p></div><hr><h2 id="configuring-log-retention" tabindex="-1">Configuring Log Retention <a class="header-anchor" href="#configuring-log-retention" aria-label="Permalink to &quot;Configuring Log Retention&quot;">​</a></h2><p>By default, audit log entries are retained indefinitely. To configure automatic purging of old entries, set the retention period in your <code>.env</code> file:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AUDIT_LOG_RETENTION_DAYS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=365</span></span></code></pre></div><p>Then run the scheduled cleanup command (add this to your cron or Supervisor):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> audit:cleanup</span></span></code></pre></div><p>Or schedule it in <code>routes/console.php</code> (Laravel 11+):</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Schedule</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;audit:cleanup&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">daily</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><hr><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><p>The audit log is read-only from the admin UI. No user — including Admin — can delete or modify individual log entries through the application interface. This ensures log integrity.</p><div class="warning custom-block"><p class="custom-block-title">Database Access</p><p>A user with direct database access could modify audit log entries. For high-security environments, consider using a separate audit log database with restricted write permissions, or forwarding logs to an external SIEM tool.</p></div><hr><h2 id="monitoring-failed-login-attempts" tabindex="-1">Monitoring Failed Login Attempts <a class="header-anchor" href="#monitoring-failed-login-attempts" aria-label="Permalink to &quot;Monitoring Failed Login Attempts&quot;">​</a></h2><p>To investigate potential brute-force attacks:</p><ol><li>Set <strong>Action</strong> filter to <code>Failed Login</code></li><li>Set a date range covering the suspicious period</li><li>Look for multiple failed attempts from the same IP address</li><li>If suspicious activity is found, use the IP address to block access at the web server or firewall level</li></ol>`,51)])])}const u=e(o,[["render",r]]);export{g as __pageData,u as default};
